// Extract request body
const body = $input.item.json.body || $input.item.json;

// Required field validation
const requiredFields = ['userId', 'userName', 'userEmail', 'preferences'];
const missing = requiredFields.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.userEmail)) {
  throw new Error(`Invalid email format: ${body.userEmail}`);
}

// Normalize preferences
const preferences = body.preferences || {};
const normalizedPrefs = {
  budget: (preferences.budget || 'moderate').toLowerCase(),
  travelStyle: (preferences.travelStyle || 'balanced').toLowerCase(),
  interests: Array.isArray(preferences.interests) ? preferences.interests : [],
  climate: (preferences.climate || 'any').toLowerCase(),
  duration: preferences.duration || '5-7 days',
  travelMonth: preferences.travelMonth || null
};

// Normalize constraints
const constraints = body.constraints || {};
const normalizedConstraints = {
  maxBudget: constraints.maxBudget || 5000,
  departureCity: constraints.departureCity || 'Not specified',
  companions: (constraints.companions || 'flexible').toLowerCase(),
  accessibility: constraints.accessibility || 'none'
};

// Calculate user profile score
const hasDetailedPrefs = normalizedPrefs.interests.length > 2;
const hasBudget = constraints.maxBudget > 0;
const hasTimeline = !!normalizedPrefs.travelMonth;
const profileCompleteness = Math.round(
  ((hasDetailedPrefs ? 40 : 0) + (hasBudget ? 30 : 0) + (hasTimeline ? 30 : 0))
);

// Build normalized request
const tripRequest = {
  // Identifiers
  requestId: `REQ-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  userId: body.userId.trim(),
  userName: body.userName.trim(),
  userEmail: body.userEmail.trim().toLowerCase(),

  // Preferences
  preferences: normalizedPrefs,
  constraints: normalizedConstraints,

  // Exclusions and priorities
  excludeRegions: body.excludeRegions || [],
  excludeDestinations: body.excludeDestinations || [],
  prioritize: body.prioritize || 'balanced',

  // Metadata
  requestedAt: new Date().toISOString(),
  profileCompleteness,
  requestSource: body.requestSource || 'web_app',
  sessionId: body.sessionId || null,

  // Processing status
  status: 'VALIDATED'
};

return { json: { tripRequest } };

// Get trip request and history
const tripRequest = $('Validate and Normalize Request').item.json.tripRequest;
const historyData = $('Fetch User Travel History').all().map(i => i.json);
const profileData = $('Fetch User Profile Data').all().map(i => i.json);

// Filter user's trips
const userTrips = historyData.filter(t => t.userId === tripRequest.userId);

// Analyze destination patterns
const destinationTypes = {};
const climatePrefs = {};
const budgetRanges = [];
const ratings = [];
const mostVisitedRegions = {};

userTrips.forEach(trip => {
  // Destination type analysis
  const type = trip.destinationType || 'unknown';
  destinationTypes[type] = (destinationTypes[type] || 0) + 1;

  // Climate preferences
  const climate = trip.climate || 'unknown';
  climatePrefs[climate] = (climatePrefs[climate] || 0) + 1;

  // Budget tracking
  if (trip.totalCost) budgetRanges.push(trip.totalCost);

  // Ratings
  if (trip.rating) ratings.push(trip.rating);

  // Regional preferences
  const region = trip.region || 'unknown';
  mostVisitedRegions[region] = (mostVisitedRegions[region] || 0) + 1;
});

// Calculate insights
const avgBudget = budgetRanges.length > 0 
  ? Math.round(budgetRanges.reduce((a, b) => a + b, 0) / budgetRanges.length)
  : 2000;

const avgRating = ratings.length > 0
  ? (ratings.reduce((a, b) => a + b, 0) / ratings.length).toFixed(1)
  : 'N/A';

const favoriteDestinationType = Object.keys(destinationTypes).sort(
  (a, b) => destinationTypes[b] - destinationTypes[a]
)[0] || 'unknown';

const preferredClimate = Object.keys(climatePrefs).sort(
  (a, b) => climatePrefs[b] - climatePrefs[a]
)[0] || 'any';

const topRegion = Object.keys(mostVisitedRegions).sort(
  (a, b) => mostVisitedRegions[b] - mostVisitedRegions[a]
)[0] || 'none';

// Recent trips (last 12 months)
const oneYearAgo = new Date();
oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
const recentTrips = userTrips.filter(t => {
  const tripDate = new Date(t.tripDate);
  return tripDate >= oneYearAgo;
});

// Build analysis
const travelAnalysis = {
  tripRequest,
  userStats: {
    totalTrips: userTrips.length,
    recentTrips: recentTrips.length,
    avgBudget,
    avgRating,
    favoriteDestinationType,
    preferredClimate,
    topRegion,
    travelFrequency: userTrips.length > 0 ? 'experienced' : 'new_traveler'
  },
  patterns: {
    destinationTypes,
    climatePrefs,
    mostVisitedRegions
  },
  recentDestinations: recentTrips.map(t => t.destination),
  highestRatedTrips: userTrips
    .filter(t => t.rating >= 4)
    .map(t => ({ destination: t.destination, rating: t.rating }))
    .slice(0, 5)
};

return [{ json: travelAnalysis }];

