const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle Anthropic content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Strip markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let recommendations;
try {
  recommendations = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude response: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Get original request
const analysis = $('Analyze Travel Patterns').item.json;
const tripRequest = analysis.tripRequest;

// Build final recommendation record
const recommendationRecord = {
  // Identifiers
  recommendationId: `REC-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  requestId: tripRequest.requestId,
  userId: tripRequest.userId,
  userName: tripRequest.userName,
  userEmail: tripRequest.userEmail,

  // Recommendations
  destinations: recommendations.recommendations || [],
  topDestination: recommendations.recommendations?.[0]?.destination || 'None',
  topMatchScore: recommendations.recommendations?.[0]?.matchScore || 0,

  // Strategy and insights
  strategy: recommendations.overallStrategy || '',
  seasonalNote: recommendations.seasonalNote || '',
  budgetTips: recommendations.budgetOptimizationTips || [],
  alternativeMonths: recommendations.alternativeMonths || [],
  confidenceScore: recommendations.confidenceScore || 0,
  dataQualityNote: recommendations.dataQualityNote || '',

  // Request context
  requestedPreferences: tripRequest.preferences,
  requestedConstraints: tripRequest.constraints,
  userTravelStats: analysis.userStats,

  // Metadata
  generatedAt: new Date().toISOString(),
  aiModel: 'claude-sonnet-4-20250514',
  status: 'GENERATED',
  viewed: false,
  bookingsMade: 0
};

return { json: { recommendationRecord, fullRecommendations: recommendations } };

const data = $('Parse AI Recommendations').item.json;
const record = data.recommendationRecord;
const full = data.fullRecommendations;

return {
  json: {
    success: true,
    recommendationId: record.recommendationId,
    userId: record.userId,
    generatedAt: record.generatedAt,
    topDestination: record.topDestination,
    totalRecommendations: record.destinations.length,
    confidenceScore: record.confidenceScore,
    recommendations: full.recommendations.map(r => ({
      destination: r.destination,
      region: r.region,
      matchScore: r.matchScore,
      estimatedBudget: r.estimatedBudget,
      bestTimeToVisit: r.bestTimeToVisit,
      highlights: r.highlights.slice(0, 3),
      insiderTips: r.insiderTips.slice(0, 2)
    })),
    strategy: full.overallStrategy,
    budgetTips: full.budgetOptimizationTips,
    message: `Found ${record.destinations.length} perfect destinations for you! Check your email for full details.`
  }
};

const users = $input.all().map(i => i.json);
const today = new Date();

// Filter users who need updated recommendations
const needsUpdate = users.filter(u => {
  if (!u.lastRecommendationDate) return true;
  const lastRec = new Date(u.lastRecommendationDate);
  const daysSince = Math.floor((today - lastRec) / (1000 * 60 * 60 * 24));
  return daysSince >= 7; // Weekly refresh
});

// Aggregate trending preferences
const trendingDestinations = {};
const popularStyles = {};
const budgetRanges = {};

users.forEach(u => {
  if (u.recentSearches) {
    u.recentSearches.forEach(s => {
      trendingDestinations[s] = (trendingDestinations[s] || 0) + 1;
    });
  }
  if (u.travelStyle) {
    popularStyles[u.travelStyle] = (popularStyles[u.travelStyle] || 0) + 1;
  }
  if (u.typicalBudget) {
    const range = u.typicalBudget < 2000 ? 'budget' : u.typicalBudget < 4000 ? 'moderate' : 'luxury';
    budgetRanges[range] = (budgetRanges[range] || 0) + 1;
  }
});

const report = {
  reportDate: today.toISOString(),
  totalUsers: users.length,
  usersNeedingUpdate: needsUpdate.length,
  trends: {
    topDestinations: Object.entries(trendingDestinations)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 10)
      .map(([dest, count]) => ({ destination: dest, searches: count })),
    popularStyles: Object.entries(popularStyles)
      .sort((a, b) => b[1] - a[1])
      .map(([style, count]) => ({ style, users: count })),
    budgetDistribution: budgetRanges
  },
  usersToUpdate: needsUpdate.map(u => ({
    userId: u.userId,
    email: u.email,
    lastUpdate: u.lastRecommendationDate || 'never'
  }))
};

return [{ json: report }];
